// Ensure build-generated TypeScript files exist so that `tsc`/Vite can run
// without first executing the heavy native generators (emscripten for the wasm
// worker, the WebGPU shader compiler). Writes a STUB only when the real file is
// absent; never clobbers a real generated file.
//
// Real generators:
//   - worker.ts  <- `npm run shader:wasm`  (emscripten; see Phase 4)
//   - shaders.ts <- `npm run shader:webgpu` (see Phase 3)
//
// This keeps typecheck/lint reproducible in CI and fresh clones where the
// native toolchains are not installed.
import { existsSync, mkdirSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";

const root = resolve(import.meta.dirname, "..");

/** @type {{path:string, content:string}[]} */
const stubs = [
  {
    path: "src/descriptor_runner/operators/wasm/worker/worker.ts",
    content:
      "/* eslint-disable */\n" +
      "// STUB: real file is generated by `npm run shader:wasm` (emscripten). See Phase 4.\n" +
      "export const wasmWorkerSrcUrl = \"\";\n",
  },
  {
    path: "src/descriptor_runner/operators/webgpu/shaders.ts",
    content:
      "/* eslint-disable */\n" +
      "// STUB: real file is generated by `npm run shader:webgpu` from *.wgsl. See Phase 3.\n" +
      "export const webgpuShaders: Record<string, string> = {};\n",
  },
];

let created = 0;
for (const { path, content } of stubs) {
  const abs = resolve(root, path);
  if (existsSync(abs)) continue;
  mkdirSync(dirname(abs), { recursive: true });
  writeFileSync(abs, content);
  console.log("stub created:", path);
  created++;
}
console.log(created === 0 ? "all generated files present (no stubs needed)" : `${created} stub(s) created`);
